import Navbar from "../components/Navbar";

function Dashboard() {
  return (
    <div>
      <Navbar />

      <div style={{ padding: "30px" }}>
        <h1>Dashboard</h1>

        <h2>Total Balance: ₹25,000</h2>

        <h3>Total Income: ₹40,000</h3>

        <h3>Total Expense: ₹15,000</h3>
      </div>
    </div>
  );
}

export default Dashboard;
